    vnb
);output y;
    input [3:0] a1, a2, a3, b1;
    input vpwr, vgnd, vpb, vnb;

    wire [4:0] sum;
      wire _n01 = a1 + a2 + a3[0] ^ b1[0];
  wire _c01 = a1 + a2 + a3[0] & b1[0];
  wire _n02 = a1 + a2 + a3[1] ^ b1[1] ^ _c01;
  wire _c02 = (a1 + a2 + a3[1] & b1[1]) | (a1 + a2 + a3[1] & _c01) | (b1[1] & _c01);
  wire _n03 = a1 + a2 + a3[2] ^ b1[2] ^ _c02;
  wire _c03 = (a1 + a2 + a3[2] & b1[2]) | (a1 + a2 + a3[2] & _c02) | (b1[2] & _c02);
  wire _n04 = a1 + a2 + a3[3] ^ b1[3] ^ _c03;
  wire _c04 = (a1 + a2 + a3[3] & b1[3]) | (a1 + a2 + a3[3] & _c03) | (b1[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};

    wire greater_than_or_equal_to_10;
    assign greater_than_or_equal_to_10 = (sum >= 10);

    assign y = (greater_than_or_equal_to_10) ? 1 : 0;

